// n8n Code node — Score & Rank Digest (VA & PR Only)
const parsedItems = $input.all().map(i => i.json);

// ---- Airtable IDs (VA & PR Focus) ----
const BASE_ID = "apptuAm73VyH7pcHA";
const TBL_IDS = {
  VA:   "tbl5uteWre548NeMZ",
  PR:   "tblzMCMKzacW1QxcW"
};
const VIEW_IDS = {
  VA:   "viw0GjDXTmRj1RWBc",
  PR:   "viw4Q3WXTrmFBaq2P"
};

// Static link for “Records with gaps”
const GAPS_URL = "https://airtable.com/appEreBPNnEyIcHnn/tble5jOajrvuhMVUW/viw1bgcEI2ohVmECT?blocks=hide";

// Pull config from Set node
let cfg = {};
try { cfg = ($items(0, 'Set: Config (ENV)')[0].json || {}).config || {}; } catch {}

const topN = {
  global: cfg.display?.topN_global ?? 5,
  VA:     cfg.display?.topN_VA ?? 5,
  PR:     cfg.display?.topN_PR ?? 3,
  keyGapsPerLine: cfg.display?.show_key_gaps_count ?? 3,
};

const th = {
  p0_score_min:   cfg.thresholds?.p0_score_min    ?? 8,
  p0_missing_min: cfg.thresholds?.p0_missing_min ?? 4,
  p1_score_min:   cfg.thresholds?.p1_score_min    ?? 4,
  p1_missing_min: cfg.thresholds?.p1_missing_min ?? 2,
};

// ---- URL builders ----
function basePath(tableKey, includeView = true) {
  const tbl  = TBL_IDS[tableKey];
  const view = includeView ? VIEW_IDS[tableKey] : null;
  if (!BASE_ID || !tbl) return null;
  const parts = [`https://airtable.com/${BASE_ID}`, tbl];
  if (view) parts.push(view);
  return parts.join("/");
}

function recordUrl(tableKey, recId) {
  const root = basePath(tableKey, cfg.links?.include_view_id ?? true);
  if (!root || !recId) return null;
  const addBlocksHide = (cfg.links?.use_blocks_hide ?? true);
  const url = `${root}/${String(recId)}`;
  return addBlocksHide ? `${url}?blocks=hide` : url;
}

function viewUrl(tableKey) {
  const root = basePath(tableKey, true);
  if (!root) return null;
  const addBlocksHide = (cfg.links?.use_blocks_hide ?? true);
  return addBlocksHide ? `${root}?blocks=hide` : root;
}

// ---------------- Weights (VA & PR Only) ----------------
const W = { VA: {}, PR: {} }; 

function add(table, names, w) { names.forEach(n => W[table][n.toLowerCase()] = w); }

// VA Weights
add('VA', ['Resume','Intro Video','Personal Email','SV Email','SV Base Rate'], 3);
add('VA', ['Resume [Link]','PI - Behavioral','PI - Cognitive','DISC','DISC [Link]'], 2);
add('VA', ['VA Source','VA Status','Endorsed to Placements','Phone Number','Photo','Priority Role','Secondary Role','Tertiary Role'], 1);

// PR Weights
add('PR', ['REQUIRED MVA','Final Client Rate','JD + C'], 3);
add('PR', ['Clients','PDEV Requirement','Company','Full/Part Time','PLACEMENT TYPE'], 2);
add('PR', ['PL STAGE'], 1);

function norm(s){ return String(s||'').replace(/\s+/g,' ').replace(/\s*:\s*$/,'').trim().toLowerCase(); }
function weight(t,f){ const k=norm(f); if (W[t]?.[k]!=null) return W[t][k]; if(t==='VA'&&(k==='disc'||k==='resume link')) return 2; return 1; }
function classify(score, miss){ if (score>=th.p0_score_min || miss>=th.p0_missing_min) return 'P0'; if (score>=th.p1_score_min || miss>=th.p1_missing_min) return 'P1'; return 'P2'; }

// ---------------- Slack helpers ----------------
const esc = (s) => String(s || "").replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;");
const link = (text, url) => (url ? `<${url}|${esc(text)}>` : esc(text));

// ---- Record detection ----
function extractRecIdFromUrl(url) {
  if (!url || typeof url !== 'string') return null;
  const m = url.match(/\/(rec[a-zA-Z0-9]{14})\b/);
  return m ? m[1] : null;
}
function getRecId(it){
  const direct = it.origin_recId || it.source_recId || it.record_id || it.id || null;
  if (direct) return String(direct);
  const candUrls = [it.record_url, it.url, it.link].filter(Boolean);
  for (const u of candUrls) {
    const rec = extractRecIdFromUrl(u);
    if (rec) return rec;
  }
  return null;
}

// Score + link
const scored = parsedItems.map(it => {
  const ws = (it.missing_fields||[]).map(f=>weight(it.table,f));
  const score = ws.reduce((a,b)=>a+b,0) + (it.extra_missing||0)*1;
  const severity = classify(score, it.missing_count);
  const recId = getRecId(it);
  const deep = it.record_url || (recId ? recordUrl(it.table, recId) : null);
  const fallback = viewUrl(it.table);

  return {
    ...it,
    score, severity,
    has_w3: ws.some(w=>w===3),
    record_url: deep || fallback || null
  };
});

// Totals
const totals = { with_gaps: 0 };
const kpisByTable = {};
for (const it of parsedItems) {
  const t = it.table;
  if (!kpisByTable[t] && it.kpis) kpisByTable[t] = { ...it.kpis };
}
totals.with_gaps = Object.values(kpisByTable).reduce((a,b)=>a+(b?.flagged??0),0);
totals.p0 = scored.filter(r=>r.severity==='P0').length;
totals.p1 = scored.filter(r=>r.severity==='P1').length;
totals.p2 = scored.filter(r=>r.severity==='P2').length;

// Sort & pick
function sortRecords(arr){
  return [...arr].sort((a,b)=>{
    if (b.score!==a.score) return b.score-a.score;
    if (b.missing_count!==a.missing_count) return b.missing_count-a.missing_count;
    return String(a.display_name).localeCompare(String(b.display_name));
  });
}

const byTable = {
  VA: sortRecords(scored.filter(r=>r.table==='VA')).slice(0, topN.VA),
  PR: sortRecords(scored.filter(r=>r.table==='PR')).slice(0, topN.PR)
};

function lineFor(r){
  const keys=(r.missing_fields||[]).slice(0, topN.keyGapsPerLine);
  const more=Math.max(0, r.missing_count-keys.length);
  const gaps=keys.join(', ')+(more>0?` (+${more} more)`:'');
  return `• ${link(r.display_name, r.record_url)} — score ${r.score}, ${r.missing_count} missing (${gaps})`;
}

const dateStr = (scored[0]?.date) || '';
const date_label = new Date(dateStr).toLocaleDateString('en-US',{month:'long',day:'numeric'});

return [{
  json: {
    date_label,
    kpis: {
      VA: kpisByTable.VA || { scanned:0, flagged:0, completeness:null },
      PR: kpisByTable.PR || { scanned:0, flagged:0, completeness:null },
      totals: { ...totals, with_gaps_url: GAPS_URL }
    },
    top_global: sortRecords(scored).slice(0, topN.global).map(r => ({ ...r, line: lineFor(r) })),
    top_by_table: {
      VA: byTable.VA.map(r => ({ ...r, line: lineFor(r) })),
      PR: byTable.PR.map(r => ({ ...r, line: lineFor(r) }))
    }
  }
}];

// n8n Code node — Parse & Normalize (VA & PR Only)
// Focuses exclusively on Virtual Assistants and Placement Requirements

const items = $input.all();

// Filtered to only include VA and PR for this specific automation
const TABLE_MAP = {
  "Virtual Assistants": "VA",
  "Placements Requirements": "PR"
};

// ---------- helpers ----------
const isStr = (v) => typeof v === "string";
const isObj = (v) => v && typeof v === "object" && !Array.isArray(v);

function extractRecIdFromUrl(url) {
  if (!isStr(url)) return null;
  const m = url.match(/\/(rec[a-zA-Z0-9]{14})\b/);
  return m ? m[1] : null;
}

function pickIdFromObj(rec) {
  if (!isObj(rec)) return null;
  const direct =
    rec?.id ?? rec?.recId ?? rec?.record_id ?? rec?.recordId ??
    rec?.origin_recId ?? rec?.airtable_id ?? rec?.rid ?? null;
  if (direct && /^rec[a-zA-Z0-9]{14}$/.test(String(direct))) return String(direct);

  const url =
    rec?.record_url ?? rec?.url ?? rec?.airtable_url ?? rec?.airtable_record_url ?? null;
  const fromUrl = extractRecIdFromUrl(url);
  if (fromUrl) return fromUrl;

  if (isObj(rec?.record)) {
    const nested = rec.record.id ?? rec.record.record_id ?? rec.record.recordId ?? null;
    if (nested && /^rec[a-zA-Z0-9]{14}$/.test(String(nested))) return String(nested);
  }

  for (const k of Object.keys(rec)) {
    const v = rec[k];
    if (isStr(v)) {
      const m = v.match(/\b(rec[a-zA-Z0-9]{14})\b/);
      if (m) return m[1];
    }
  }
  return null;
}

function parseJsonLoose(val) {
  if (Array.isArray(val)) return val;
  if (isObj(val)) return [val];
  if (!isStr(val)) return null;

  let s = val.trim();
  if (!s) return null;

  try {
    const once = JSON.parse(s);
    if (Array.isArray(once)) return once;
    if (isObj(once)) return [once];
    if (isStr(once)) {
      const t = once.trim();
      if (t.startsWith("[") || t.startsWith("{")) {
        const twice = JSON.parse(t);
        if (Array.isArray(twice)) return twice;
        if (isObj(twice)) return [twice];
      }
    }
  } catch {}

  try {
    const deEscaped = s
      .replace(/^"(.*)"$/s, "$1")
      .replace(/\\"/g, '"')
      .replace(/\\n/g, "\n")
      .replace(/\\\\/g, "\\");
    const once = JSON.parse(deEscaped);
    if (Array.isArray(once)) return once;
    if (isObj(once)) return [once];
  } catch {}

  return null;
}

function regexExtractEntries(raw) {
  if (!isStr(raw)) return [];
  const s = raw;
  const results = [];
  const re = /\{[^{}]*?"id"\s*:\s*"(?<id>rec[a-zA-Z0-9]{14})"[^{}]*?\}/g;
  let m;
  while ((m = re.exec(s)) !== null) {
    const chunk = m[0];
    const id = m.groups.id;
    const nameMatch = chunk.match(/"name"\s*:\s*"([^"]+)"/) ||
                      chunk.match(/"display_name"\s*:\s*"([^"]+)"/) ||
                      chunk.match(/"title"\s*:\s*"([^"]+)"/);
    const name = nameMatch ? nameMatch[1] : "";
    const mcMatch = chunk.match(/"missing_count"\s*:\s*(\d+)/) ||
                    chunk.match(/"missingcount"\s*:\s*(\d+)/);
    const missing_count = mcMatch ? Number(mcMatch[1]) : null;

    const missArrMatch = chunk.match(/"missing"\s*:\s*\[([^\]]*)\]/) ||
                         chunk.match(/"missing_fields"\s*:\s*\[([^\]]*)\]/);
    let missing_fields = [];
    if (missArrMatch) {
      const list = missArrMatch[1];
      const qre = /"([^"]+)"/g;
      let qm;
      while ((qm = qre.exec(list)) !== null) missing_fields.push(qm[1]);
    }

    results.push({
      id,
      name,
      missing_fields,
      missing_count: missing_count ?? (missing_fields.length || 0),
    });
  }
  return results;
}

// ---------- main ----------
const out = [];

for (const it of items) {
  const row = it.json ?? it;
  const fullTable = row["Table"];

  // Skip if table is not Virtual Assistants or Placements Requirements
  if (!TABLE_MAP[fullTable]) continue; 

  const table = TABLE_MAP[fullTable];
  const date = row["Date Scrubbed"] || row["Created"] || null;
  const kpis = {
    scanned: row["Scanned"] ?? null,
    flagged: row["Flagged"] ?? null,
    completeness: row["Completeness %"] ?? null,
  };
  const runId = row["Run ID"] || null;

  const jsonRaw = row["Display Missing (JSON)"] ?? row["display_missing_json"] ?? null;

  let entries = parseJsonLoose(jsonRaw);
  if (!entries) {
    const rescued = regexExtractEntries(String(jsonRaw ?? ""));
    if (rescued.length) entries = rescued;
  }

  if (!entries || !entries.length) continue;

  for (const rec of entries) {
    const nameRaw = String(rec?.name ?? rec?.display_name ?? rec?.title ?? "").trim();
    const url = rec?.record_url ?? rec?.url ?? rec?.airtable_url ?? null;
    const recId = pickIdFromObj(rec) || extractRecIdFromUrl(url);

    const fields = Array.isArray(rec?.missing) ? rec.missing
                  : Array.isArray(rec?.missing_fields) ? rec.missing_fields
                  : [];

    const mcount = (rec?.missing_count != null) ? Number(rec.missing_count)
                  : (rec?.missingcount != null) ? Number(rec.missingcount)
                  : fields.length;

    out.push({
      json: {
        table,
        date,
        display_name: nameRaw || (recId ? `${recId.slice(0,5)}…${recId.slice(-4)}` : "Untitled"),
        missing_fields: fields,
        extra_missing: Math.max(0, mcount - fields.length),
        missing_count: mcount,
        kpis,
        source_run_id: runId,
        source_table_label: fullTable,
        origin_recId: recId || null,
        record_url: url || null,
      }
    });
  }
}

return out;

// Input: ONE item (the daily digest object)
// Output: { blocks } for Slack formatted for VA & PR

const d = $input.item.json;

// ---- Airtable IDs (VA & PR Only) ----
const BASE_ID = "apptuAm73VyH7pcHA";
const TBL_IDS = {
  VA:   "tbl5uteWre548NeMZ",
  PR:   "tblzMCMKzacW1QxcW"
};
const VIEW_IDS = {
  VA:   "viw0GjDXTmRj1RWBc",
  PR:   "viw4Q3WXTrmFBaq2P"
};

// link prefs from upstream digest
const INCLUDE_VIEW = d?.config?.links?.include_view_id ?? true;
const HIDE_BLOCKS  = d?.config?.links?.use_blocks_hide ?? true;
const GAPS_URL      = d?.kpis?.totals?.with_gaps_url || 
                     "https://airtable.com/apptuAm73VyH7pcHA/tbl0yFjYm1N3Boq8w/viwf3nL5O9YjhBXxs?blocks=hide";

// ---- KPIs ----
const k = d.kpis || { VA:{}, PR:{}, totals:{} };

const gapsCount = (k.VA.flagged || 0) + (k.PR.flagged || 0);
const gapsLink  = `<${GAPS_URL}|Records with gaps: ${gapsCount}>`;

const totalsLine =
  `VA ${k.VA.scanned || 0} • PR ${k.PR.scanned || 0}` +
  `  |  ${gapsLink}` +
  `  |  P0 ${k.totals.p0 || 0} • P1 ${k.totals.p1 || 0} • P2 ${k.totals.p2 || 0}`;

// ---- Helpers ----
const SHOW_GAPS = d?.config?.display?.show_key_gaps_count ?? 3;
const esc = (s) => String(s || "").replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;");
const link = (url, text) => (url ? `<${url}|${esc(text)}>` : esc(text));

function pickSourceRecId(it) {
  return it.origin_recId || it.source_recId || it.record_id || it.id || null;
}

function buildUrl(tableKey, recId, fallbackUrl) {
  if (fallbackUrl) return fallbackUrl;
  const tbl  = TBL_IDS[tableKey];
  const view = INCLUDE_VIEW ? VIEW_IDS[tableKey] : null;
  if (!BASE_ID || !tbl) return "";
  const parts = [`https://airtable.com/${BASE_ID}`, tbl];
  if (view) parts.push(view);
  if (recId) parts.push(recId);
  const base = parts.join("/");
  return HIDE_BLOCKS ? `${base}?blocks=hide` : base;
}

function getName(it) {
  const n = (it.display_name || it.name || it.title || "").toString().trim();
  if (n) return n;
  const id = pickSourceRecId(it);
  return id ? `${id.slice(0,5)}…${id.slice(-4)}` : "Untitled";
}

function makeBullet(it) {
  const tableKey = it.table;
  const srcId    = pickSourceRecId(it);
  const url      = buildUrl(tableKey, srcId, it.record_url);
  const name     = getName(it);
  const fields   = (it.key_gaps || it.missing_fields || []);
  const preview  = fields.slice(0, SHOW_GAPS);
  const baseCnt  = (it.missing_count != null) ? it.missing_count : fields.length;
  const more     = Math.max(0, baseCnt - preview.length);
  const moreTag  = more > 0 ? ` (+${more} more)` : "";
  const missTxt  = `${baseCnt} missing`;
  const gapsTxt  = preview.length ? ` (${preview.join(", ")}${moreTag})` : "";
  return `• ${link(url, name)} — ${missTxt}${gapsTxt}`;
}

function completenessEmoji(pct) {
  if (pct == null) return "⚫️";
  const val = Math.round(pct * 100);
  return val >= 85 ? "🟢" : val >= 50 ? "🟡" : "🔴";
}

function sectionHeader(label, completeness) {
  const pct = completeness != null ? Math.round(completeness * 100) : "—";
  const emoji = completenessEmoji(completeness);
  return `*${label}: Record Completeness ${pct}% ${emoji}*\n_Top Records with Missing Fields:_`;
}

function section(label, items = [], completeness = null) {
  const forcedCompleteness = (Array.isArray(items) && items.length === 0) ? 1 : completeness;
  const body = items.length ? items.map(makeBullet).join("\n") : "_No items_";
  return [
    { type: "section", text: { type: "mrkdwn", text: sectionHeader(label, forcedCompleteness) } },
    { type: "section", text: { type: "mrkdwn", text: body } },
    { type: "divider" },
  ];
}

// ---- Assemble blocks ----
const blocks = [
  { type: "header", text: { type: "plain_text", text: `Scrubbing Digest: VA & PR — ${d.date_label}`, emoji: true } },
  { type: "section", text: { type: "mrkdwn", text: `_${totalsLine}_` } },
  { type: "divider" },
  ...section("Virtual Assistants", d.top_by_table?.VA || [], (d.kpis?.VA?.completeness ?? null)),
  ...section("Placement Requirements", d.top_by_table?.PR || [], (d.kpis?.PR?.completeness ?? null)),
];

return [{ json: { blocks } }];

