function weight(t,f){ const k=norm(f); if (W[t]?.[k]!=null) return W[t][k]; if(t==='VA'&&(k==='disc'||k==='resume link')) return 2; return 1; }
function classify(score, miss){ if (score>=th.p0_score_min || miss>=th.p0_missing_min) return 'P0'; if (score>=th.p1_score_min || miss>=th.p1_missing_min) return 'P1'; return 'P2'; }

