const esc = (s) => String(s || "").replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;");
const link = (text, url) => (url ? `<${url}|${esc(text)}>` : esc(text));

// ---- Record detection ----
function extractRecIdFromUrl(url) {
  if (!url || typeof url !== 'string') return null;
  const m = url.match(/\/(rec[a-zA-Z0-9]{14})\b/);
  return m ? m[1] : null;
}
function getRecId(it){
  const direct = it.origin_recId || it.source_recId || it.record_id || it.id || null;
  if (direct) return String(direct);
  const candUrls = [it.record_url, it.url, it.link].filter(Boolean);
  for (const u of candUrls) {
    const rec = extractRecIdFromUrl(u);
    if (rec) return rec;
  }
  return null;
}

// Score + link
const scored = parsedItems.map(it => {
  const ws = (it.missing_fields||[]).map(f=>weight(it.table,f));
  const score = ws.reduce((a,b)=>a+b,0) + (it.extra_missing||0)*1;
  const severity = classify(score, it.missing_count);
  const recId = getRecId(it);
  const deep = it.record_url || (recId ? recordUrl(it.table, recId) : null);
  const fallback = viewUrl(it.table);

  return {
    ...it,
    score, severity,
    has_w3: ws.some(w=>w===3),
    record_url: deep || fallback || null
  };
});

// Totals
const totals = { with_gaps: 0 };
const kpisByTable = {};
for (const it of parsedItems) {
  const t = it.table;
  if (!kpisByTable[t] && it.kpis) kpisByTable[t] = { ...it.kpis };
}
totals.with_gaps = Object.values(kpisByTable).reduce((a,b)=>a+(b?.flagged??0),0);
totals.p0 = scored.filter(r=>r.severity==='P0').length;
totals.p1 = scored.filter(r=>r.severity==='P1').length;
totals.p2 = scored.filter(r=>r.severity==='P2').length;

// Sort & pick
function sortRecords(arr){
  return [...arr].sort((a,b)=>{
    if (b.score!==a.score) return b.score-a.score;
    if (b.missing_count!==a.missing_count) return b.missing_count-a.missing_count;
    return String(a.display_name).localeCompare(String(b.display_name));
  });
}

const byTable = {
