  PR: sortRecords(scored.filter(r=>r.table==='PR')).slice(0, topN.PR)
};

function lineFor(r){
  const keys=(r.missing_fields||[]).slice(0, topN.keyGapsPerLine);
  const more=Math.max(0, r.missing_count-keys.length);
  const gaps=keys.join(', ')+(more>0?` (+${more} more)`:'');
  return `• ${link(r.display_name, r.record_url)} — score ${r.score}, ${r.missing_count} missing (${gaps})`;
}

