const items = $input.all();

// Filtered to only include VA and PR for this specific automation
const TABLE_MAP = {
  "Virtual Assistants": "VA",
  "Placements Requirements": "PR"
};

// ---------- helpers ----------
const isStr = (v) => typeof v === "string";
const isObj = (v) => v && typeof v === "object" && !Array.isArray(v);

function extractRecIdFromUrl(url) {
  if (!isStr(url)) return null;
  const m = url.match(/\/(rec[a-zA-Z0-9]{14})\b/);
  return m ? m[1] : null;
}

function pickIdFromObj(rec) {
  if (!isObj(rec)) return null;
  const direct =
    rec?.id ?? rec?.recId ?? rec?.record_id ?? rec?.recordId ??
    rec?.origin_recId ?? rec?.airtable_id ?? rec?.rid ?? null;
  if (direct && /^rec[a-zA-Z0-9]{14}$/.test(String(direct))) return String(direct);

  const url =
    rec?.record_url ?? rec?.url ?? rec?.airtable_url ?? rec?.airtable_record_url ?? null;
  const fromUrl = extractRecIdFromUrl(url);
  if (fromUrl) return fromUrl;

  if (isObj(rec?.record)) {
    const nested = rec.record.id ?? rec.record.record_id ?? rec.record.recordId ?? null;
    if (nested && /^rec[a-zA-Z0-9]{14}$/.test(String(nested))) return String(nested);
  }

  for (const k of Object.keys(rec)) {
    const v = rec[k];
    if (isStr(v)) {
      const m = v.match(/\b(rec[a-zA-Z0-9]{14})\b/);
      if (m) return m[1];
    }
  }
  return null;
}

function parseJsonLoose(val) {
  if (Array.isArray(val)) return val;
  if (isObj(val)) return [val];
  if (!isStr(val)) return null;

  let s = val.trim();
  if (!s) return null;

  try {
    const once = JSON.parse(s);
    if (Array.isArray(once)) return once;
    if (isObj(once)) return [once];
    if (isStr(once)) {
      const t = once.trim();
      if (t.startsWith("[") || t.startsWith("{")) {
        const twice = JSON.parse(t);
        if (Array.isArray(twice)) return twice;
        if (isObj(twice)) return [twice];
      }
    }
  } catch {}

  try {
    const deEscaped = s
      .replace(/^"(.*)"$/s, "$1")
      .replace(/\\"/g, '"')
      .replace(/\\n/g, "\n")
      .replace(/\\\\/g, "\\");
    const once = JSON.parse(deEscaped);
    if (Array.isArray(once)) return once;
    if (isObj(once)) return [once];
  } catch {}

  return null;
}

function regexExtractEntries(raw) {
  if (!isStr(raw)) return [];
  const s = raw;
  const results = [];
  const re = /\{[^{}]*?"id"\s*:\s*"(?<id>rec[a-zA-Z0-9]{14})"[^{}]*?\}/g;
  let m;
  while ((m = re.exec(s)) !== null) {
    const chunk = m[0];
    const id = m.groups.id;
    const nameMatch = chunk.match(/"name"\s*:\s*"([^"]+)"/) ||
                      chunk.match(/"display_name"\s*:\s*"([^"]+)"/) ||
                      chunk.match(/"title"\s*:\s*"([^"]+)"/);
    const name = nameMatch ? nameMatch[1] : "";
    const mcMatch = chunk.match(/"missing_count"\s*:\s*(\d+)/) ||
                    chunk.match(/"missingcount"\s*:\s*(\d+)/);
    const missing_count = mcMatch ? Number(mcMatch[1]) : null;

    const missArrMatch = chunk.match(/"missing"\s*:\s*\[([^\]]*)\]/) ||
                         chunk.match(/"missing_fields"\s*:\s*\[([^\]]*)\]/);
    let missing_fields = [];
    if (missArrMatch) {
      const list = missArrMatch[1];
      const qre = /"([^"]+)"/g;
      let qm;
      while ((qm = qre.exec(list)) !== null) missing_fields.push(qm[1]);
    }

    results.push({
      id,
      name,
      missing_fields,
      missing_count: missing_count ?? (missing_fields.length || 0),
    });
  }
  return results;
}

// ---------- main ----------
const out = [];

for (const it of items) {
  const row = it.json ?? it;
  const fullTable = row["Table"];

  // Skip if table is not Virtual Assistants or Placements Requirements
  if (!TABLE_MAP[fullTable]) continue; 

  const table = TABLE_MAP[fullTable];
  const date = row["Date Scrubbed"] || row["Created"] || null;
  const kpis = {
    scanned: row["Scanned"] ?? null,
    flagged: row["Flagged"] ?? null,
    completeness: row["Completeness %"] ?? null,
  };
  const runId = row["Run ID"] || null;

  const jsonRaw = row["Display Missing (JSON)"] ?? row["display_missing_json"] ?? null;

  let entries = parseJsonLoose(jsonRaw);
  if (!entries) {
    const rescued = regexExtractEntries(String(jsonRaw ?? ""));
    if (rescued.length) entries = rescued;
  }

  if (!entries || !entries.length) continue;

  for (const rec of entries) {
    const nameRaw = String(rec?.name ?? rec?.display_name ?? rec?.title ?? "").trim();
    const url = rec?.record_url ?? rec?.url ?? rec?.airtable_url ?? null;
    const recId = pickIdFromObj(rec) || extractRecIdFromUrl(url);

    const fields = Array.isArray(rec?.missing) ? rec.missing
                  : Array.isArray(rec?.missing_fields) ? rec.missing_fields
                  : [];

    const mcount = (rec?.missing_count != null) ? Number(rec.missing_count)
                  : (rec?.missingcount != null) ? Number(rec.missingcount)
                  : fields.length;

    out.push({
      json: {
        table,
        date,
        display_name: nameRaw || (recId ? `${recId.slice(0,5)}…${recId.slice(-4)}` : "Untitled"),
        missing_fields: fields,
        extra_missing: Math.max(0, mcount - fields.length),
        missing_count: mcount,
        kpis,
        source_run_id: runId,
        source_table_label: fullTable,
        origin_recId: recId || null,
        record_url: url || null,
      }
    });
  }
}

return out;

